#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

// Function to perform DFS
int dfs(int node, int level, int *supervisors, int *clubs, int *levels, int *count, int N, int X) {
    if (level == 0) return 1;
    int total = 0;
    for (int i = 0; i < N; i++) {
        if (supervisors[i] == node && clubs[i] == clubs[node] && levels[i] == levels[node] - 1) {
            total = (total + dfs(i, level - 1, supervisors, clubs, levels, count, N, X)) % MOD;
        }
    }
    return total;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, X;
        scanf("%d %d", &N, &X);
        int *supervisors = (int *)malloc((N - 1) * sizeof(int));
        int *clubs = (int *)malloc(N * sizeof(int));
        int *levels = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N - 1; i++) {
            scanf("%d", &supervisors[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &clubs[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &levels[i]);
        }
        for (int i = 0; i < N; i++) {
            int count = dfs(i, levels[i], supervisors, clubs, levels, NULL, N, X);
            printf("%d\n", count);
        }
        free(supervisors);
        free(clubs);
        free(levels);
    }
    return 0;
}

