import java.util.Scanner;

public class Main {
    static final int MOD = 1000000007;

    // Function to perform DFS
    public static int dfs(int node, int level, int[] supervisors, int[] clubs, int[] levels, int N, int X) {
        if (level == 0) return 1;
        int total = 0;
        for (int i = 0; i < N; i++) {
            if (supervisors[i] == node && clubs[i] == clubs[node] && levels[i] == levels[node] - 1) {
                total = (total + dfs(i, level - 1, supervisors, clubs, levels, N, X)) % MOD;
            }
        }
        return total;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int X = sc.nextInt();
            int[] supervisors = new int[N - 1];
            int[] clubs = new int[N];
            int[] levels = new int[N];
            for (int i = 0; i < N - 1; i++) {
                supervisors[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                clubs[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                levels[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                int count = dfs(i, levels[i], supervisors, clubs, levels, N, X);
                System.out.println(count);
